"""
MKT Original — Matthew 25
Output: data/commentary/mkt-original/matthew.json (adds ch25)
"""
import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: Per-verse Greek lexical commentary for Matthew 25; covers the Ten Virgins,
#   Talents, and Sheep/Goats parables. Strictly Greek lexical/syntactic focus.
# CHANGE? If verse keys change in data/interlinear/matthew.json, update dict keys here.
# VERIFY: Run script; confirm "wrote data/commentary/mkt-original/matthew.json".
#   Then check ch25 has 46 verses matching the interlinear.

NEW_DATA = {
  "25": {
    "1": "<p><strong>tote homoiōthēsetai hē basileia tōn ouranōn deka parthenois</strong> — <em>then the kingdom of heaven will be likened to ten virgins</em> — <em>Tote</em> (then) ties the parable to the preceding eschatological discourse. <em>Parthenois</em> (virgins, maidens) — unmarried young women attending the bridal party. <em>Aitines laboũsai tas lampadas heautōn exēlthon eis hypantēsin tou nymphiou</em> (who having taken their lamps went out to meet the bridegroom) — <em>hypantēsin</em> (meeting, encounter — legal/ceremonial term for going out to receive an arriving dignitary).</p>",
    "2": "<p><strong>pente de ex autōn ēsan mōrai kai pente phronimoi</strong> — <em>five of them were foolish and five were wise</em> — <em>Mōrai</em> (foolish, dull — cf. 5:22; 7:26; 23:17) and <em>phronimoi</em> (wise, prudent, practically intelligent — cf. 7:24; 10:16; 24:45). The split is exactly equal; the parable is not about a minority of fools but equal distribution, making the outcome sobering.</p>",
    "3": "<p><strong>hai gar mōrai labousai tas lampadas autōn ouk elabon meth\' heautōn elaion</strong> — <em>for the foolish having taken their lamps did not take oil with them</em> — <em>Elaion</em> (olive oil) for the lamps. The foolishness is not having lamps but failing to bring adequate oil for an unpredictably long wait. The present participle <em>labousai</em> (having taken) is followed by the aorist negation <em>ouk elabon</em> — the taking of lamps and the not-taking of extra oil are simultaneous oversights.</p>",
    "4": "<p><strong>hai de phronimoi elabon elaion en tois aggeioīs</strong> — <em>but the wise took oil in their vessels</em> — <em>Aggeia</em> (vessels, containers — from <em>aggos</em> = container) = the extra flasks carried alongside the lamps. <em>Meta tōn lampadōn heautōn</em> (with their lamps) — the wise carry both the lamp and the reserve supply.</p>",
    "5": "<p><strong>chronizōntos de tou nymphiou enystaxan pãsai kai ekoimēthēsan</strong> — <em>the bridegroom delaying, they all slumbered and slept</em> — <em>Chronizō</em> (to be delayed, to take time — cf. 24:48) — the bridegroom\xe2\x80\x99s delay is deliberate in the story; in the allegory it represents the unexpectedly long interval before the Parousia. <em>Enystaxan</em> (aorist of <em>nystazō</em> = to nod off, doze) and <em>ekoimēthēsan</em> (fell asleep) — both verbs; all ten sleep, wise and foolish alike.</p>",
    "6": "<p><strong>mesēs de nyktos kraugē gegonen idou ho nymphios exerchetai</strong> — <em>in the middle of the night a cry has come: behold the bridegroom is coming</em> — <em>Mesēs de nyktos</em> (in the middle of the night) = midnight, the most unexpected hour. <em>Kraugē</em> (a shout, cry — from <em>kraugazō</em>) — sudden announcement. <em>Exerchesthe eis apantēsin</em> (go out to the meeting) — the formal escort-reception.</p>",
    "7": "<p><strong>ēgeiran pasai hai parthenoi ekeinai kai ekosmēsan tas lampadas heautōn</strong> — <em>all those virgins arose and trimmed their lamps</em> — <em>Egeírō</em> (to raise, arouse, awaken) — all ten respond equally to the cry. <em>Kosmēō</em> (to put in order, trim, adorn) the lamps — either trimming the wick or refilling the oil reservoir. The crisis reveals the hidden difference.</p>",
    "8": "<p><strong>hai de mōrai tais phronimois eipon</strong> — <em>the foolish said to the wise</em> — <em>Dote hēmin ek tou elaiou hymōn</em> (give us some of your oil) — <em>dote</em> (give, aorist imperative) + <em>ek tou elaiou</em> (from the oil, partitive genitive). <em>Hoti hai lampades hēmōn sbennyntai</em> (because our lamps are going out) — <em>sbennymi</em> (present passive: are being extinguished, going out) — the present tense shows the crisis is immediate.</p>",
    "9": "<p><strong>mēpote ou mē arkesē̄ hēmin kai hymin</strong> — <em>lest there might not be enough for us and for you</em> — <em>Mēpote</em> (lest, perhaps — a cautionary conjunction). <em>Ou mē arkesē̄</em> (might by no means be sufficient) — the wise are not selfish; they recognize the oil is not transferable — preparedness cannot be borrowed at the last moment. <em>Poreuesthe mallon pros tous pōlountas</em> (go rather to the sellers) — <em>mallon</em> (rather, instead) redirects them to the only available source.</p>",
    "10": "<p><strong>aperchoménōn de autōn agorásai ēlthen ho nymphios</strong> — <em>while they were going to buy, the bridegroom came</em> — The genitive absolute <em>aperchoménōn... agorásai</em> (while they were going to buy) frames their absence as the decisive moment. <em>Ai hetoimoi eisēlthon met\' autou eis tous gamous</strong> (the prepared ones went in with him to the wedding feast) — <em>hetoimoi</em> (the ready ones, from <em>hetoimos</em>). <em>Ekleisthē hē thyra</em> (the door was shut) — the aorist passive is definitive: the door has been shut and remains shut.</p>",
    "11": "<p><strong>hysteron de erchontai kai hai loipai parthenoi legousai</strong> — <em>later the rest of the virgins also come saying</em> — <em>Hysteron</em> (later, afterwards) — they arrive after the closing. <em>Kyrie kyrie anoixon hēmin</em> (Lord, Lord, open for us) — the double <em>kyrie</em> echo 7:21-22 (not everyone who says Lord, Lord). The plea is urgent but belated.</p>",
    "12": "<p><strong>ho de apokritheis eipen amēn legō hymin ouk oida hymas</strong> — <em>answering he said: truly I say to you, I do not know you</em> — <em>Ouk oida hymas</em> (I do not know you) is the language of covenant recognition; to be known by God is to be in covenant relationship (cf. 7:23 <em>oudepote egnōn hymas</em>). The <em>amēn</em> (truly) solemnizes the exclusion.</p>",
    "13": "<p><strong>grēgoreite oun hoti ouk oidate tēn hēmeran oude tēn hōran</strong> — <em>watch therefore because you do not know the day nor the hour</em> — <em>Grēgoreō</em> (to be awake, alert — cf. 24:42) summarizes the parable\xe2\x80\x99s lesson. The specific ignorance is of <em>hēmera</em> (day) and <em>hōra</em> (hour) — neither the date nor the time. The parable\xe2\x80\x99s answer to this ignorance is preparedness (<em>hetoimos</em>), not calculation.</p>",
    "14": "<p><strong>hōsper gar anthrōpos apodēmōn ekalesen tous idious doulous</strong> — <em>for it is just as a man going on a journey called his own servants</em> — <em>Apodēmeō</em> (to be away from home, travel abroad) — the departure initiates the stewardship period. <em>Tous idious doulous</em> (his own servants) = his personal household slaves. <em>Paredōken autois ta hyparchonta autou</em> (entrusted to them his possessions) — <em>paradidōmi</em> (to hand over, entrust) in the stewardship sense.</p>",
    "15": "<p><strong>kai hō men edōken pente talanta</strong> — <em>and to one he gave five talents</em> — <em>Talanton</em> (talent) = the largest monetary unit; 1 talent = 6000 denarii (~20 years\xe2\x80\x99 wages). The distribution is <em>kata tēn idian dynamin</em> (according to his own ability/capacity) — each servant receives what he can handle, not equal amounts. The differentiated trust is the premise of the parable.</p>",
    "16": "<p><strong>poreutheis ho ta pente talanta labōn ērgasato en autois</strong> — <em>having gone the one who received five talents worked with them</em> — <em>Ērgasato</em> (aorist of <em>ergazomai</em> = to work, to trade) — the five-talent servant immediately (<em>poreutheis</em> = having gone = right away) put the capital to work. <em>Ērgasato en autois</em> (worked with them) — active deployment of the entrusted resources.</p>",
    "17": "<p><strong>hōsautōs kai ho ta dyo</strong> — <em>likewise also the one with two</em> — <em>Hōsautōs</em> (in the same way, likewise) — the two-talent servant behaves identically in proportion. The parallelism emphasizes that the principle applies regardless of the quantity entrusted.</p>",
    "18": "<p><strong>ho de to hen labōn apelthōn ōryxen gēn kai ekrysen to argyrion tou kyriou autou</strong> — <em>but the one who received the one, having gone, dug in the ground and hid his master's silver</em> — <em>Ōryxen gēn</em> (dug earth) — burying valuables was a recognized ancient security practice; but in this context it represents refusal to risk, refusal to trade. <em>To argyrion tou kyriou autou</em> (the silver of his master) — he acknowledges it belongs to the master but treats preservation as sufficient.</p>",
    "19": "<p><strong>meta de chronon polun erchetai ho kyrios tōn doulōn ekeinōn</strong> — <em>after a long time the master of those servants comes</em> — <em>Meta chronon polun</em> (after much time) — the delay is explicit; this grounds the expectation of a long inter-advent period in the parable\xe2\x80\x99s structure. <em>Kai synaïrei logon met\' autōn</em> (and settles accounts with them) — <em>synaïrō logon</em> (to settle accounts, to reckon up a ledger — papyrus commercial term).</p>",
    "20": "<p><strong>proseuthēn ho ta pente talanta labōn prosēnegken alla pente talanta</strong> — <em>the one who had received five talents came forward bringing another five</em> — <em>Proseutheis</em> (coming forward, presenting himself) — the presentation is formal. <em>Alla pente talanta</em> (another five talents) = 100% return. <em>Kyrie pente talanta moi paredōkas idou alla pente talanta ekerdēsa</em> (Lord, you entrusted me five talents; behold I have gained another five) — <em>kerdainō</em> (to gain, to earn profit) aorist.</p>",
    "21": "<p><strong>eu doule agathe kai piste</strong> — <em>well done, good and faithful servant</em> — <em>Eu</em> (well! — the adverb of approbation) + <em>doule agathe kai piste</em> (good and faithful servant) — <em>agathos</em> (morally good) and <em>pistos</em> (trustworthy, faithful). <em>Epi oliga ēs pistos epi pollōn se katastēsō</em> (over few things you were faithful, over many things I will appoint you) — the principle of proportional promotion. <em>Eiselthe eis tēn charan tou kyriou sou</em> (enter into the joy of your master) — <em>chara</em> (joy) as the content of reward.</p>",
    "22": "<p><strong>proseuthēn de kai ho ta dyo talanta</strong> — <em>and also the one with two talents came forward</em> — The two-talent servant presents with identical percentage return: <em>alla dyo talanta ekerdēsa</em> (I have gained another two talents). The response he receives is verbatim the same as the five-talent servant (v.23 = v.21), confirming that faithfulness is measured proportionally, not by absolute amount.</p>",
    "23": "<p><strong>eu doule agathe kai piste epi oliga ēs pistos</strong> — <em>well done, good and faithful servant, over few things you were faithful</em> — The exact repetition of the master\xe2\x80\x99s commendation affirms that the two-talent servant is equally rewarded. <em>Epi pollōn se katastēsō</em> (over many I will appoint you) — both servants receive identical promotion, regardless of the five vs. two starting point.</p>",
    "24": "<p><strong>proseuthēn de kai ho to hen talanton eilēphōs eipen</strong> — <em>the one who had received one talent also came forward and said</em> — <em>Eilēphōs</em> (perfect active participle of <em>lambanō</em>: having received and holding) — the perfect tense emphasizes he still has the original talent in his possession. His speech reveals his reasoning: <em>egnōn se hoti sklēros ei anthrōpos</em> (I knew you as a hard man).</p>",
    "25": "<p><strong>kai phobētheis apelthōn ekrysa to talanton sou en tē̄ gē̄</strong> — <em>and having been afraid I went and hid your talent in the ground</em> — <em>Phobētheis</em> (having been afraid, aorist passive participle) — fear is the stated motive for inaction. <em>Ekrysa</em> (I hid, aorist) — the hiding is presented as a cautious protective measure. <em>Ide echeis to son</em> (here you have what is yours) — the servant considers returning the original principal as sufficient; he has not lost anything.</p>",
    "26": "<p><strong>ponēre doule kai oknēre</strong> — <em>wicked and lazy servant</em> — <em>Ponēros</em> (wicked, evil) and <em>oknēros</em> (shrinking, lazy, hesitant — from <em>oknos</em> = reluctance, shrinking) are the master\xe2\x80\x99s characterization. The charge is not theft but failure to deploy. <em>Ēdeis hoti therizo hopou ouk espeira kai synagō hothen ou dieskorp isa</em> — the master accepts the servant\xe2\x80\x99s characterization of him and asks: given that assessment, why did you not at minimum deposit the money?</p>",
    "27": "<p><strong>edei se oun balein ta arguria mou tois trapezitais</strong> — <em>you ought therefore to have deposited my silver with the bankers</em> — <em>Trapezitai</em> (money-changers, bankers — from <em>trapeza</em> = table/counter) = those who lend at interest. <em>Kai elthōn egō ekomisamen an to emon syn tokō̧</em> (and coming I would have received my own with interest) — <em>tokos</em> (interest, usury — from <em>tiktō</em> = to beget, birth) = money \xe2\x80\x9cbegotten\xe2\x80\x9d from money. Even passive interest-bearing was preferable to burial.</p>",
    "28": "<p><strong>arate oun ap\' autou to talanton kai dote tō̄ echonti ta deka talanta</strong> — <em>take therefore from him the talent and give to the one who has ten talents</em> — <em>Arate</em> (take away, aorist imperative of <em>airō</em>) — the removal is judicial. The transfer to the one with ten is not about maximizing returns but about the kingdom principle: entrusted resources that produce nothing are reassigned to those who will deploy them.</p>",
    "29": "<p><strong>tō̄ gar echonti panti dothēsetai kai perisseuēthēsetai</strong> — <em>for to the one who has, all will be given and he will have abundance</em> — The principle <em>tō echonti... tō de mē echonti</em> (to the one who has... from the one who does not have) is a paradox of kingdom economics: faithful stewardship generates further entrusting; failure to use generates loss. <em>Arthēsetai ap\' autou</em> (will be taken from him) — the divine passive.</p>",
    "30": "<p><strong>kai ton achreon doulon ekballete eis to skotos to exōteron</strong> — <em>cast the useless servant into the outer darkness</em> — <em>Achreos</em> (useless, unprofitable — from <em>a-</em> + <em>chreia</em> = without utility/use) — the one-talent servant is declared <em>achreos</em>: not wicked in an active sense but failing his purpose. <em>Eis to skotos to exōteron</em> with the weeping-and-gnashing formula (cf. 8:12; 22:13; 24:51) — the standard Matthean judgment formula.</p>",
    "31": "<p><strong>hotan de elthē̄ ho huios tou anthrōpou en tē̄ doxē̄ autou</strong> — <em>when the Son of Man comes in his glory</em> — The Sheep and Goats pericope opens the final judgment scene of Matthew. <em>En tē̄ doxē̄ autou</em> (in his glory) + <em>kai pantes hoi aggeloi met\' autou</em> (and all the angels with him) — the full eschatological court. <em>Kathisei epi thronou doxēs autou</em> (he will sit on the throne of his glory) — echoes 19:28 (<em>palingenesia</em>).</p>",
    "32": "<p><strong>kai synachthēsontai emprosthen autou panta ta ethnē</strong> — <em>and all the nations will be gathered before him</em> — <em>Panta ta ethnē</em> (all the nations) — the universal scope of this judgment. <em>Aphorisei autous ap\' allēlōn</strong> (he will separate them from one another) — <em>aphorizō</em> (to separate, to set apart) is the technical term for sorting (cf. 13:49). <em>Hōsper ho poimēn aphorizei ta probata apo tōn eriphōn</em> (as a shepherd separates the sheep from the goats) — the contrast is between <em>probata</em> (sheep) and <em>eriphoi</em> (goats — young male goats).</p>",
    "33": "<p><strong>kai stēsei ta men probata ek dexiōn autou ta de eriphia ex euōnymōn</strong> — <em>and he will place the sheep on his right and the goats on the left</em> — <em>Ek dexiōn</em> (on the right) = the place of honor and blessing; <em>ex euōnymōn</em> (on the left — literally <em>euōnymos</em> = well-named, a euphemism for the inauspicious left). The spatial separation is symbolic of final determination.</p>",
    "34": "<p><strong>deute hoi eulogēmenoi tou patros mou</strong> — <em>come, the blessed of my Father</em> — <em>Deute</em> (come!, plural imperative) — an invitation. <em>Hoi eulogēmenoi</em> (the blessed ones — perfect passive participle of <em>eulogeō</em>) = those who have received divine blessing. <em>Klēronomēsate tēn hētoimasmenēn hymin basileian apo katabolēs kosmou</em> (inherit the kingdom prepared for you from the foundation of the world) — <em>apo katabolēs kosmou</em> (from the foundation/casting-down of the world) — the kingdom\xe2\x80\x99s preparation is pre-temporal.</p>",
    "35": "<p><strong>epeinasa gar kai edōkate moi phagein</strong> — <em>for I was hungry and you gave me food</em> — The six categories of merciful action: hunger, thirst, stranger, naked, sick, prisoner. <em>Phagein</em> (to eat, aorist infinitive) — provision of food. <em>Xenos ēmēn kai synēgagete me</em> (I was a stranger and you gathered me in) — <em>synagō</em> (to gather, welcome in) used for hospitality to foreign travelers.</p>",
    "36": "<p><strong>gymnos kai periebalete me</strong> — <em>naked and you clothed me</em> — <em>Gymnos</em> (naked, stripped down to the undergarment, inadequately clothed) — not necessarily fully nude but without adequate outer covering. <em>Ēsthenēsa kai epeskepsasthe me</em> (I was sick and you visited me) — <em>episkeptomai</em> (to look upon, to visit, to attend to — the same root as <em>episkopē</em>). <em>En phylakē̄ kai ēlthete pros me</em> (in prison and you came to me).</p>",
    "37": "<p><strong>tote apokrithēsontai autō̄ hoi dikaioi legontes</strong> — <em>then the righteous will answer him saying</em> — <em>Hoi dikaioi</em> (the righteous ones) — their identity at the judgment. The four-fold <em>pote se eidomen</em> questions (vv. 37-39) express genuine surprise: <em>when did we see you hungry... thirsty... a stranger... naked?</em> The ignorance is authentic; their service was not performed to earn reward.</p>",
    "38": "<p><strong>pote de se eidomen xenon kai sunēgagomen</strong> — <em>when did we see you a stranger and welcomed you?</em> — <em>Xenos</em> (stranger, foreigner, guest) — the repeated <em>pote</em> (when?) questions in vv.37-39 show the righteous did not consciously serve the king; they served the needy without knowing the eschatological significance.</p>",
    "39": "<p><strong>pote de se eidomen asthenounta ē en phylakē̄ kai ēlthomen pros se</strong> — <em>when did we see you sick or in prison and came to you?</em> — The final two service categories complete the six. The pattern of service in vv.35-36, 38-39 is exhaustive of basic human need: physical sustenance, clothing, social welcome, medical care, prison-visiting.</p>",
    "41": "<p><strong>poreuesthe ap\' emou hoi katērarmenoi eis to pyr to aiōnion</strong> — <em>depart from me, the cursed ones, into the eternal fire</em> — <em>Poreuesthe</em> (go!, present imperative) — a dismissal, contrasting with the invitation <em>deute</em> (come!) to the righteous. <em>Hoi katērarmenoi</em> (the cursed ones — perfect passive participle of <em>kataraomai</em>) vs. <em>hoi eulogēmenoi</em> (the blessed ones, v.34). <em>To pyr to aiōnion to hētoimasmenon tō̄ diabolō̄ kai tois angelois autou</em> — the fire was <em>prepared for the devil and his angels</em>, not originally for humans; human exclusion from the kingdom is a secondary, tragic outcome.</p>",
    "42": "<p><strong>epeinasa gar kai ouk edōkate moi phagein</strong> — <em>for I was hungry and you did not give me food</em> — The six acts of omission exactly mirror the six acts of commission in vv.35-36. The judgment rests on failure to act (<em>ouk edōkate... ouk epotisate... ou synēgagete... ou periebalете... ou epeskepsasthe... ou ēlthete</em>) — repeated aorist negations of each service category.</p>",
    "43": "<p><strong>xenos ēmēn kai ou synēgagete me</strong> — <em>I was a stranger and you did not welcome me</em> — <em>Ou synēgagete</em> (you did not gather in, you did not welcome) — the refusal of hospitality to the stranger. The parallel structure with vv.35-36 makes the symmetry explicit: every act of mercy has its corresponding act of negligence.</p>",
    "44": "<p><strong>tote apokrithēsontai kai autoi legontes</strong> — <em>then they also will answer saying</em> — <em>Kai autoi</em> (they also) — the goats also express surprise, mirroring the sheep\xe2\x80\x99s genuine bewilderment. <em>Kyrie pote se eidomen peinōnta ē dipōsnta ē xenon ē gymnom ē asthenounta ē en phylakē̄</em> — the full catalog of neglected needs is recited as a single question.</p>",
    "45": "<p><strong>tote apokrithēsetai autois legōn amēn legō hymin</strong> — <em>then he will answer them saying: truly I say to you</em> — The <em>amēn</em> solemn introduction precedes the definitive explanation: <em>eph\' hoson ouk epoiēsate heni toutōn tōn elachistōn oude emoi epoiēsate</em> (to the extent you did not do it to one of the least of these, neither did you do it to me). The negative identification (<em>ouk epoiēsate</em>) is as absolute as the positive (<em>epoiēsate</em>, v.40).</p>",
    "46": "<p><strong>kai apeleusontai houtoi eis kolasin aiōnion</strong> — <em>and these will go away into eternal punishment</em> — <em>Kolasis aiōnios</em> (eternal punishment/correction — <em>kolasis</em> from <em>kolazō</em> = to curtail, to punish) vs. <em>zōē̄n aiōnion</em> (eternal life). Both carry the same adjective <em>aiōnios</em> (of the age to come, eternal/age-long) — the duration and quality of both outcomes are parallel. The same adjective applies to both, ruling out an asymmetric reading of one as temporary.</p>"
  }
}

comm = load_comm('mkt-original', 'matthew')
merge_comm(comm, NEW_DATA)
save_comm('mkt-original', 'matthew', comm)

print('Done.')
ch = '25'
print(f'  ch{ch}: {len(comm.get(ch, {}))} verses')
